from agent import *from models.products import *import simplejsonimport reXCAT = ['Varumärken', 'Nyheter']DUPE_PRODS = []def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.queue(Request('https://eleven.se/smink/lappar?page=12'), process_prodlist, {'cat': 'Smink|Läppar'})    session.queue(Request('https://eleven.se/hudvard/ansiktsvard/ansiktsmask'), process_prodlist, {'cat': 'Hudvård|Ansikte|Ansiktsmask'})    session.queue(Request('https://eleven.se/'), process_frontpage, {})def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//ul[@class="navigation__menu"]/li/a')    for cat in cats:        name = cat.xpath('text()').string()        url = cat.xpath('@href').string()        if name and name not in XCAT:            session.queue(Request(url), process_category, dict(cat=name))def process_category(data, context, session):    strip_namespace(data)    subcats = data.xpath('//div[@class="page-intro__sublinks"]/a')    for subcat in subcats:        name = subcat.xpath('div/text()').string()        url = subcat.xpath('@href').string()        if name and url:            session.queue(Request(url), process_prodlist, dict(cat=context['cat']+'|'+name))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//div[@class="product-list__list"]/div')    for prod in prods:        name = prod.xpath('@aria-label').string()        url = prod.xpath('a/@href').string()        ssid = prod.xpath('.//div/@data-family-id').string()        if ssid:            session.queue(Request(url), process_product, dict(context, name=name, url=url, ssid=ssid))    next_url = data.xpath('//li/a[contains(@aria-label, "next page")]/@href').string()    if next_url:        session.queue(Request(next_url), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat']    product.ssid = context['ssid'].replace('base-', '')    product.manufacturer = data.xpath('//span[@class="brand-link__text"]/text()').string()    product.sku = data.xpath('//div[contains(@class, "product-page")]/@data-sku').string()    if product.ssid not in DUPE_PRODS:        revs_url = 'https://eleven.se/json/productreviews/fetch?baseProductId=base-%s&page=1' % product.ssid        session.do(Request(revs_url), process_reviews, dict(product=product))    if product.reviews:        session.emit(product)        DUPE_PRODS.append(product.ssid)def process_reviews(data, context, session):    strip_namespace(data)    product = context['product']    resp = simplejson.loads(data.content)    revs = resp.get('productReviews', [])    for rev in revs:        language = rev.get('language')        if not language or language not in ('sv', 'se'):            continue        review = Review()        review.url = product.url        review.type = 'user'        review.ssid = rev['id']        date = rev.get('createdAt')        if date:            review.date = date.split('T')[0]        author = rev.get('consumer')        if author:            author_name = author.get('displayName')            author_ssid = author.get('id')            if author_name and author_ssid:                review.authors.append(Person(name=author_name, ssid=author_ssid))            elif author_name:                review.authors.append(Person(name=author_name, ssid=author_name))        grade_overall = rev.get('stars')        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        excerpt = rev.get('content')        if excerpt:            excerpt = remove_emoji(excerpt.replace('\n', ' ').replace('\\n', ' ')).strip()            if excerpt:                review.properties.append(ReviewProperty(type='excerpt', value=excerpt.strip()))                product.reviews.append(review)    # 404 after first page    offset = context.get('offset', 0) + 10    revs_cnt = resp.get('pagination', {}).get('totalCount', 0)    if offset < revs_cnt:        next_page = context.get('page', 1) + 1        revs_url = 'https://eleven.se/json/productreviews/fetch?baseProductId=base-%s&page=%s' % (product.ssid, next_page)        session.do(Request(revs_url), process_reviews, dict(product=product, offset=offset, page=next_page))